class Solution {
public:
    vector<vector<string>> findWordLadders(
        string startWord,
        string targetWord,
        vector<string>& wordList
    ) {
        unordered_set<string> dict(wordList.begin(), wordList.end());
        vector<vector<string>> result;

        if (!dict.count(targetWord)) return result;

        unordered_map<string, vector<string>> parent;
        unordered_map<string, int> level;
        queue<string> q;

        q.push(startWord);
        level[startWord] = 0;

        int L = startWord.size();
        int minLevel = INT_MAX;

        while (!q.empty()) {
            int sz = q.size();
            unordered_set<string> usedThisLevel;

            while (sz--) {
                string word = q.front();
                q.pop();
                int currLevel = level[word];

                if (currLevel >= minLevel) continue;

                for (int i = 0; i < L; i++) {
                    string next = word;
                    for (char c = 'a'; c <= 'z'; c++) {
                        if (c == word[i]) continue;
                        next[i] = c;

                        if (dict.count(next)) {
                            if (!level.count(next)) {
                                level[next] = currLevel + 1;
                                q.push(next);
                                parent[next].push_back(word);
                                usedThisLevel.insert(next);
                            } 
                            else if (level[next] == currLevel + 1) {
                                parent[next].push_back(word);
                            }

                            if (next == targetWord) {
                                minLevel = currLevel + 1;
                            }
                        }
                    }
                }
            }

            for (auto &w : usedThisLevel) {
                dict.erase(w);
            }
        }

        if (!level.count(targetWord)) return result;

        vector<string> path;
        backtrack(targetWord, startWord, parent, path, result);
        return result;
    }

private:
    void backtrack(
        string word,
        string startWord,
        unordered_map<string, vector<string>>& parent,
        vector<string>& path,
        vector<vector<string>>& result
    ) {
        path.push_back(word);

        if (word == startWord) {
            vector<string> seq = path;
            reverse(seq.begin(), seq.end());
            result.push_back(seq);
        } else {
            for (auto &p : parent[word]) {
                backtrack(p, startWord, parent, path, result);
            }
        }

        path.pop_back();
    }
};

