class Solution:
    def findWordLadders(self, startWord, targetWord, wordList):
        wordSet = set(wordList)
        result = []

        if targetWord not in wordSet:
            return result

        parent = defaultdict(list)
        level = {startWord: 0}
        q = deque([startWord])

        L = len(startWord)
        minLevel = float('inf')

        while q:
            size = len(q)
            usedThisLevel = set()

            for _ in range(size):
                word = q.popleft()
                currLevel = level[word]

                if currLevel >= minLevel:
                    continue

                for i in range(L):
                    for c in range(ord('a'), ord('z') + 1):
                        ch = chr(c)
                        if ch == word[i]:
                            continue

                        nextWord = word[:i] + ch + word[i+1:]

                        if nextWord in wordSet:
                            if nextWord not in level:
                                level[nextWord] = currLevel + 1
                                q.append(nextWord)
                                parent[nextWord].append(word)
                                usedThisLevel.add(nextWord)
                            elif level[nextWord] == currLevel + 1:
                                parent[nextWord].append(word)

                            if nextWord == targetWord:
                                minLevel = currLevel + 1

            for w in usedThisLevel:
                wordSet.remove(w)

        if targetWord not in level:
            return result

        path = []
        self.backtrack(targetWord, startWord, parent, path, result)
        return result

    def backtrack(self, word, startWord, parent, path, result):
        path.append(word)

        if word == startWord:
            result.append(path[::-1])
        else:
            for p in parent[word]:
                self.backtrack(p, startWord, parent, path, result)

        path.pop()

