typedef struct Node {
    char word[MAX_WORD_LEN];
    struct Node* next;
} Node;

typedef struct {
    Node* buckets[HASH_SIZE];
} HashSet;

typedef struct ParentNode {
    char word[MAX_WORD_LEN];
    struct ParentNode* next;
} ParentNode;

typedef struct {
    char word[MAX_WORD_LEN];
    ParentNode* parents;
} ParentEntry;

typedef struct {
    ParentEntry entries[MAX_WORDS];
    int size;
} ParentMap;

typedef struct {
    char word[MAX_WORD_LEN];
    int level;
} LevelEntry;

typedef struct {
    LevelEntry entries[MAX_WORDS];
    int size;
} LevelMap;

typedef struct {
    char words[MAX_PATH_LEN][MAX_WORD_LEN];
    int front, rear, size;
} Queue;

unsigned int hash(const char* str) {
    unsigned int hash = 5381;
    int c;
    while ((c = *str++))
        hash = ((hash << 5) + hash) + c;
    return hash % HASH_SIZE;
}

void initHashSet(HashSet* set) {
    for (int i = 0; i < HASH_SIZE; i++)
        set->buckets[i] = NULL;
}

void insertHashSet(HashSet* set, const char* word) {
    unsigned int idx = hash(word);
    Node* newNode = (Node*)malloc(sizeof(Node));
    strcpy(newNode->word, word);
    newNode->next = set->buckets[idx];
    set->buckets[idx] = newNode;
}

bool containsHashSet(HashSet* set, const char* word) {
    unsigned int idx = hash(word);
    Node* curr = set->buckets[idx];
    while (curr) {
        if (strcmp(curr->word, word) == 0)
            return true;
        curr = curr->next;
    }
    return false;
}

void eraseHashSet(HashSet* set, const char* word) {
    unsigned int idx = hash(word);
    Node* curr = set->buckets[idx];
    Node* prev = NULL;

    while (curr) {
        if (strcmp(curr->word, word) == 0) {
            if (prev)
                prev->next = curr->next;
            else
                set->buckets[idx] = curr->next;
            free(curr);
            return;
        }
        prev = curr;
        curr = curr->next;
    }
}

void freeHashSet(HashSet* set) {
    for (int i = 0; i < HASH_SIZE; i++) {
        Node* curr = set->buckets[i];
        while (curr) {
            Node* temp = curr;
            curr = curr->next;
            free(temp);
        }
    }
}

void initParentMap(ParentMap* map) {
    map->size = 0;
}

void addParent(ParentMap* map, const char* word, const char* parent) {
    for (int i = 0; i < map->size; i++) {
        if (strcmp(map->entries[i].word, word) == 0) {
            ParentNode* newNode = (ParentNode*)malloc(sizeof(ParentNode));
            strcpy(newNode->word, parent);
            newNode->next = map->entries[i].parents;
            map->entries[i].parents = newNode;
            return;
        }
    }

    strcpy(map->entries[map->size].word, word);
    ParentNode* newNode = (ParentNode*)malloc(sizeof(ParentNode));
    strcpy(newNode->word, parent);
    newNode->next = NULL;
    map->entries[map->size].parents = newNode;
    map->size++;
}

ParentNode* getParents(ParentMap* map, const char* word) {
    for (int i = 0; i < map->size; i++) {
        if (strcmp(map->entries[i].word, word) == 0)
            return map->entries[i].parents;
    }
    return NULL;
}

void freeParentMap(ParentMap* map) {
    for (int i = 0; i < map->size; i++) {
        ParentNode* curr = map->entries[i].parents;
        while (curr) {
            ParentNode* temp = curr;
            curr = curr->next;
            free(temp);
        }
    }
}

void initLevelMap(LevelMap* map) {
    map->size = 0;
}

void setLevel(LevelMap* map, const char* word, int level) {
    for (int i = 0; i < map->size; i++) {
        if (strcmp(map->entries[i].word, word) == 0) {
            map->entries[i].level = level;
            return;
        }
    }
    strcpy(map->entries[map->size].word, word);
    map->entries[map->size].level = level;
    map->size++;
}

int getLevel(LevelMap* map, const char* word, bool* found) {
    for (int i = 0; i < map->size; i++) {
        if (strcmp(map->entries[i].word, word) == 0) {
            *found = true;
            return map->entries[i].level;
        }
    }
    *found = false;
    return -1;
}

void initQueue(Queue* q) {
    q->front = 0;
    q->rear = 0;
    q->size = 0;
}

void enqueue(Queue* q, const char* word) {
    strcpy(q->words[q->rear], word);
    q->rear = (q->rear + 1) % MAX_PATH_LEN;
    q->size++;
}

void dequeue(Queue* q, char* word) {
    strcpy(word, q->words[q->front]);
    q->front = (q->front + 1) % MAX_PATH_LEN;
    q->size--;
}

bool isQueueEmpty(Queue* q) {
    return q->size == 0;
}

int queueSize(Queue* q) {
    return q->size;
}

char*** result;
int* resultSizes;
int resultCount;
int resultCapacity;

void backtrack(const char* word, const char* startWord, ParentMap* parent,
               char path[][MAX_WORD_LEN], int pathLen) {
    strcpy(path[pathLen], word);
    pathLen++;

    if (strcmp(word, startWord) == 0) {
        if (resultCount >= resultCapacity) {
            resultCapacity *= 2;
            result = (char***)realloc(result, resultCapacity * sizeof(char**));
            resultSizes = (int*)realloc(resultSizes, resultCapacity * sizeof(int));
        }

        result[resultCount] = (char**)malloc(pathLen * sizeof(char*));
        for (int i = 0; i < pathLen; i++) {
            result[resultCount][i] = (char*)malloc(MAX_WORD_LEN);
            strcpy(result[resultCount][i], path[pathLen - 1 - i]);
        }
        resultSizes[resultCount] = pathLen;
        resultCount++;
    } else {
        ParentNode* parents = getParents(parent, word);
        while (parents) {
            backtrack(parents->word, startWord, parent, path, pathLen);
            parents = parents->next;
        }
    }
}

int comparePaths(const void* a, const void* b) {
    char** pathA = *(char***)a;
    char** pathB = *(char***)b;
    int sizeA = resultSizes[*(int*)a];
    int sizeB = resultSizes[*(int*)b];

    int minSize = sizeA < sizeB ? sizeA : sizeB;
    for (int i = 0; i < minSize; i++) {
        int cmp = strcmp(pathB[i], pathA[i]);
        if (cmp != 0) return cmp;
    }
    return sizeB - sizeA;
}

void findWordLadders(char* startWord, char* targetWord, char wordList[][MAX_WORD_LEN], int wordCount) {
    HashSet dict;
    initHashSet(&dict);

    for (int i = 0; i < wordCount; i++)
        insertHashSet(&dict, wordList[i]);

    resultCount = 0;
    resultCapacity = 100;
    result = (char***)malloc(resultCapacity * sizeof(char**));
    resultSizes = (int*)malloc(resultCapacity * sizeof(int));

    if (!containsHashSet(&dict, targetWord)) return;

    ParentMap parent;
    LevelMap level;
    Queue q;

    initParentMap(&parent);
    initLevelMap(&level);
    initQueue(&q);

    enqueue(&q, startWord);
    setLevel(&level, startWord, 0);

    int L = strlen(startWord);
    int minLevel = INT_MAX;

    while (!isQueueEmpty(&q)) {
        int sz = queueSize(&q);
        HashSet usedThisLevel;
        initHashSet(&usedThisLevel);

        while (sz--) {
            char word[MAX_WORD_LEN];
            dequeue(&q, word);

            bool found;
            int currLevel = getLevel(&level, word, &found);

            if (currLevel >= minLevel) continue;

            for (int i = 0; i < L; i++) {
                char next[MAX_WORD_LEN];
                strcpy(next, word);

                for (char c = 'a'; c <= 'z'; c++) {
                    if (c == word[i]) continue;
                    next[i] = c;

                    if (containsHashSet(&dict, next)) {
                        bool levelFound;
                        int nextLevel = getLevel(&level, next, &levelFound);

                        if (!levelFound) {
                            setLevel(&level, next, currLevel + 1);
                            enqueue(&q, next);
                            addParent(&parent, next, word);
                            insertHashSet(&usedThisLevel, next);
                        } else if (nextLevel == currLevel + 1) {
                            addParent(&parent, next, word);
                        }

                        if (strcmp(next, targetWord) == 0) {
                            minLevel = currLevel + 1;
                        }
                    }
                }
            }
        }

        for (int i = 0; i < HASH_SIZE; i++) {
            Node* curr = usedThisLevel.buckets[i];
            while (curr) {
                eraseHashSet(&dict, curr->word);
                curr = curr->next;
            }
        }
        freeHashSet(&usedThisLevel);
    }

    bool found;
    getLevel(&level, targetWord, &found);

    if (found) {
        char path[MAX_PATH_LEN][MAX_WORD_LEN];
        backtrack(targetWord, startWord, &parent, path, 0);
    }

    freeHashSet(&dict);
    freeParentMap(&parent);
}

