class Solution {

    public List<List<String>> findWordLadders(
            String startWord,
            String targetWord,
            List<String> wordList
    ) {
        Set<String> dict = new HashSet<>(wordList);
        List<List<String>> result = new ArrayList<>();

        if (!dict.contains(targetWord)) return result;

        Map<String, List<String>> parent = new HashMap<>();
        Map<String, Integer> level = new HashMap<>();
        Queue<String> queue = new ArrayDeque<>();

        queue.offer(startWord);
        level.put(startWord, 0);

        int L = startWord.length();
        int minLevel = Integer.MAX_VALUE;

        while (!queue.isEmpty()) {
            int size = queue.size();
            Set<String> usedThisLevel = new HashSet<>();

            while (size-- > 0) {
                String word = queue.poll();
                int currLevel = level.get(word);

                if (currLevel >= minLevel) continue;

                char[] arr = word.toCharArray();

                for (int i = 0; i < L; i++) {
                    char original = arr[i];

                    for (char c = 'a'; c <= 'z'; c++) {
                        if (c == original) continue;

                        arr[i] = c;
                        String next = new String(arr);

                        if (dict.contains(next)) {
                            if (!level.containsKey(next)) {
                                level.put(next, currLevel + 1);
                                queue.offer(next);
                                parent.computeIfAbsent(next, k -> new ArrayList<>()).add(word);
                                usedThisLevel.add(next);
                            } else if (level.get(next) == currLevel + 1) {
                                parent.get(next).add(word);
                            }

                            if (next.equals(targetWord)) {
                                minLevel = currLevel + 1;
                            }
                        }
                    }
                    arr[i] = original;
                }
            }

            for (String w : usedThisLevel) {
                dict.remove(w);
            }
        }

        if (!level.containsKey(targetWord)) return result;

        List<String> path = new ArrayList<>();
        backtrack(targetWord, startWord, parent, path, result);
        return result;
    }

    private void backtrack(
            String word,
            String startWord,
            Map<String, List<String>> parent,
            List<String> path,
            List<List<String>> result
    ) {
        path.add(word);

        if (word.equals(startWord)) {
            List<String> seq = new ArrayList<>(path);
            Collections.reverse(seq);
            result.add(seq);
        } else {
            if (parent.containsKey(word)) {
                for (String p : parent.get(word)) {
                    backtrack(p, startWord, parent, path, result);
                }
            }
        }

        path.remove(path.size() - 1);
    }
}

