class Solution {
    findWordLadders(startWord, targetWord, wordList) {
        const dict = new Set(wordList);
        const result = [];

        if (!dict.has(targetWord)) return result;

        const parent = new Map();   // word -> [parents]
        const level = new Map();    // word -> distance
        const queue = [];

        queue.push(startWord);
        level.set(startWord, 0);

        const L = startWord.length;
        let minLevel = Infinity;

        while (queue.length > 0) {
            let size = queue.length;
            const usedThisLevel = new Set();

            while (size--) {
                const word = queue.shift();
                const currLevel = level.get(word);

                if (currLevel >= minLevel) continue;

                for (let i = 0; i < L; i++) {
                    for (let c = 97; c <= 122; c++) {
                        const ch = String.fromCharCode(c);
                        if (ch === word[i]) continue;

                        const next =
                            word.slice(0, i) + ch + word.slice(i + 1);

                        if (dict.has(next)) {
                            if (!level.has(next)) {
                                level.set(next, currLevel + 1);
                                queue.push(next);
                                if (!parent.has(next)) parent.set(next, []);
                                parent.get(next).push(word);
                                usedThisLevel.add(next);
                            } else if (level.get(next) === currLevel + 1) {
                                parent.get(next).push(word);
                            }

                            if (next === targetWord) {
                                minLevel = currLevel + 1;
                            }
                        }
                    }
                }
            }

            for (const w of usedThisLevel) {
                dict.delete(w);
            }
        }

        if (!level.has(targetWord)) return result;

        const path = [];
        this.backtrack(targetWord, startWord, parent, path, result);
        return result;
    }

    backtrack(word, startWord, parent, path, result) {
        path.push(word);

        if (word === startWord) {
            result.push([...path].reverse());
        } else if (parent.has(word)) {
            for (const p of parent.get(word)) {
                this.backtrack(p, startWord, parent, path, result);
            }
        }

        path.pop();
    }
}
